import { ViewDialog } from "@/components/common/dialogs/ViewDialog";
import {
  Application,
  ApplicationSmartScreeningResult,
} from "../types/applications.types";
import { useApplicationsActions } from "../hooks/useApplicationsActions";
import { useEffect, useState } from "react";
import { set } from "zod";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";

interface SmartScreeningDialogProps {
  open: boolean;
  setOpen: (open: boolean) => void;
  application: Application;
}

export function SmartScreeningDialog({
  open,
  setOpen,
  application,
}: SmartScreeningDialogProps) {
  const { runSmartScreening, clearApiError, apiError, loading } =
    useApplicationsActions();
  const [screeningResult, setScreeningResult] =
    useState<ApplicationSmartScreeningResult | null>(null);

  async function smartScreening() {
    clearApiError();
    try {
      const result = await runSmartScreening(application.id);
      setScreeningResult(result);
    } catch (error) {
      console.error("Error running smart screening:", error);
    }
  }

  useEffect(() => {
    if (!open || !application) return;

    //=== checking only if missing aiScore and aiDecision, as summary not important.
    if (!application.aiScore || !application?.aiDecision) {
      smartScreening();
    } else {
      setScreeningResult({
        candidateName: application.fullName,
        score: application.aiScore,
        summary: application.aiSummary || "",
        decision: application.aiDecision,
      });
    }
  }, [open, application]);

  return (
    <ViewDialog
      title="Smart Screening Results"
      isOpen={open}
      onClose={() => setOpen(false)}
    >
      {application?.aiScore && !screeningResult && (
        <div>
          <Alert>
            <AlertDescription>
              This application has already been screened. You can run the smart
              screening again by clicking the below button, but it will
              overwrite the existing score, summary, and decision.
            </AlertDescription>
          </Alert>
          <div className="flex justify-end items-end">
            <Button className="mt-4" onClick={smartScreening}>
              Re-run Smart Screening
            </Button>
          </div>
        </div>
      )}

      {screeningResult && (
        <div>
          <h3 className="text-xl">{screeningResult.candidateName}</h3>
          <p>Score: {screeningResult.score}</p>
          <p>Summary: {screeningResult.summary}</p>
          <p>Decision: {screeningResult.decision}</p>
        </div>
      )}

      {apiError && (
        <div className="mb-4">
          <Alert variant="destructive">
            <AlertDescription>
              {apiError.message ||
                "An error occurred while running the smart screening."}
            </AlertDescription>
          </Alert>
        </div>
      )}

      {loading && <p>Running smart screening...</p>}
    </ViewDialog>
  );
}
